import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is a golf handicap?", a: "A golf handicap is a numerical measure of a golfer's potential playing ability. It allows players of widely different skill levels to compete fairly on any course. A lower handicap indicates a better golfer - a scratch golfer (handicap 0) is expected to shoot par, while a 20 handicap player is expected to shoot about 20 over par." },
  { q: "How is a Handicap Index calculated under the World Handicap System?", a: "The World Handicap System (WHS) takes your 20 most recent score differentials, selects the best 8, averages them, and multiplies by 0.96. Score Differential = (Gross Score - Course Rating)  x  (113 / Slope Rating). The resulting Handicap Index is portable - it works on any course worldwide." },
  { q: "What is Course Rating and Slope Rating?", a: "Course Rating estimates the expected score of a scratch golfer on that specific course under normal conditions. Slope Rating (range 55-155, standard 113) measures the relative difficulty for a bogey golfer compared to a scratch golfer. A slope of 113 is considered 'standard' difficulty." },
  { q: "What is a Course Handicap and how is it different from a Handicap Index?", a: "Handicap Index is your portable, universal number. Course Handicap converts it for a specific course and tee: Course Handicap = Handicap Index  x  (Slope Rating / 113) + (Course Rating - Par). This is the number you actually subtract from your gross score to get your net score for that round." },
  { q: "What is a 'scratch' golfer?", a: "A scratch golfer has a Handicap Index of 0.0 and is expected to score par on a course with a Slope Rating of 113. In practice, scratch golfers average about 72-74 strokes on a par-72 course. Only about 2% of golfers are scratch or better." },
  { q: "What handicap is considered a beginner vs. advanced?", a: "Handicap categories: 0-9 (low handicap, advanced), 10-18 (mid handicap, typical club golfer), 19-28 (high handicap, recreational), 29-54 (maximum, beginner). The average men's handicap in the US is about 14.2; average women's is about 27.5." },
  { q: "How many rounds do I need to establish a Handicap Index?", a: "Under the WHS, you can establish a Handicap Index with as few as 3 rounds (9-hole rounds count as half rounds). The system uses the best differential from your first few rounds until you have enough scores to use the full best-8-of-20 calculation." },
  { q: "What is a net score in golf?", a: "Net score = Gross score - Course Handicap. If you shoot 92 and your course handicap is 18, your net score is 74. Net scores allow golfers of different abilities to compete head-to-head - a 74 net from an 18 handicapper is equivalent to a 74 net from a 5 handicapper." },
];

const TYPICAL_HANDICAPS = [
  ["Beginner (first year)", "30-54", "Score: 100-120+ on par-72"],
  ["High handicap recreational", "19-28", "Score: 90-100 on par-72"],
  ["Average club golfer", "14-18", "Score: 85-95 on par-72"],
  ["Mid-range player", "10-13", "Score: 82-90 on par-72"],
  ["Low handicap", "5-9", "Score: 77-85 on par-72"],
  ["Near-scratch", "1-4", "Score: 73-78 on par-72"],
  ["Scratch golfer", "0", "Score: ~72 (par) on par-72"],
  ["Plus handicap (elite)", "+1 to +10", "Score: better than par regularly"],
];

export default function GolfHandicapCalculator() {
  const [grossScore, setGrossScore] = useState(90);
  const [courseRating, setCourseRating] = useState(72.1);
  const [slopeRating, setSlopeRating] = useState(125);
  const [handicapIndex, setHandicapIndex] = useState(15.4);
  const [par, setPar] = useState(72);

  const scoreDiff = (grossScore - courseRating) * (113 / slopeRating);
  const courseHandicap = handicapIndex * (slopeRating / 113) + (courseRating - par);
  const netScore = grossScore - Math.round(courseHandicap);

  return (
    <>
      <SEOHead
        title="Free Golf Handicap Calculator Online - Calculate Score Differential and Course Handicap Instantly | CalcHive"
        description="Free online golf handicap calculator. Calculate golf score differential and course handicap using the World Handicap System instantly. 100% free for all golfers, no signup required."
        canonical="/golf-handicap-calculator"
        keywords="free golf handicap calculator, golf handicap calculator online free, world handicap system calculator free, golf score differential calculator free, course handicap calculator free"
        category="Sports Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-lime-600 dark:text-lime-400 bg-lime-50 dark:bg-lime-950/50 px-3 py-1 rounded-full mb-4 inline-block">Everyday</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Golf Handicap Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free golf handicap calculator to estimate score differential and course handicap using the World Handicap System. This golf handicap calculator online free also works as a world handicap system calculator free, golf score differential calculator free, and course handicap calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <p className="text-sm font-bold text-muted-foreground uppercase tracking-wide mb-4">Round Details</p>
          <div className="space-y-5 mb-6">
            <SliderInput id="gross" label="Gross Score (strokes)" value={grossScore} min={60} max={150} step={1} onChange={setGrossScore} format={v => `${v} strokes`} testId="input-gross" />
            <SliderInput id="cr" label="Course Rating" value={courseRating} min={60} max={80} step={0.1} onChange={setCourseRating} format={v => v.toFixed(1)} testId="input-cr" helpText="Found on scorecard - scratch golfer's expected score" />
            <SliderInput id="slope" label="Slope Rating" value={slopeRating} min={55} max={155} step={1} onChange={setSlopeRating} format={v => `${v}`} testId="input-slope" helpText="Standard = 113; higher = harder for average player" />
            <SliderInput id="par" label="Course Par" value={par} min={68} max={74} step={1} onChange={setPar} format={v => `${v}`} testId="input-par" />
          </div>
          <p className="text-sm font-bold text-muted-foreground uppercase tracking-wide mb-4">Your Handicap Index</p>
          <div className="mb-8">
            <SliderInput id="hi" label="Handicap Index" value={handicapIndex} min={0} max={54} step={0.1} onChange={setHandicapIndex} format={v => v.toFixed(1)} testId="input-hi" />
          </div>
          <motion.div key={`${grossScore}-${courseRating}-${slopeRating}-${handicapIndex}-${par}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-lime-500 to-lime-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Score Differential</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-diff">{scoreDiff.toFixed(1)}</p>
              <p className="text-white/70 text-sm mt-1">(Gross - Course Rating)  x  113  x  Slope</p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {[
                { label: "Course Handicap", value: Math.round(courseHandicap).toString() },
                { label: "Net Score", value: `${netScore} (${netScore - par > 0 ? "+" : ""}${netScore - par} vs par)` },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Golf Handicap for Free</h2>
          <p className="text-muted-foreground leading-relaxed">The World Handicap System (adopted globally in 2020) standardizes handicap calculation across all golf organizations. The system uses your best recent score differentials to create a portable Handicap Index that works on any rated course worldwide.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-3">
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Step 1: Score Differential (per round)</p>
              <p>Differential = (Gross Score - Course Rating)  x  (113  x  Slope Rating)</p>
            </div>
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Step 2: Handicap Index (over time)</p>
              <p>Handicap Index = Average of best 8 of last 20 differentials  x  0.96</p>
            </div>
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Step 3: Course Handicap (per course)</p>
              <p>Course HC = Handicap Index  x  (Slope  x  113) + (Course Rating - Par)</p>
            </div>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How the World Handicap System Works</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Player Level", "Handicap Index", "Typical Score on Par-72"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {TYPICAL_HANDICAPS.map(([level, hi, score]) => (
                  <tr key={level} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{level}</td>
                    <td className="py-2.5 px-4 text-lime-600 dark:text-lime-400 font-bold">{hi}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{score}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Golf Score Differential Calculator for All Golfers</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Rounds Recorded", "Differentials Used", "Note"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["3 rounds", "Lowest 1", "Scaled by 0.96"],
                  ["4 rounds", "Lowest 1", ""],
                  ["5 rounds", "Lowest 1", ""],
                  ["6 rounds", "Lowest 2", "Average  x  0.96"],
                  ["7-8 rounds", "Lowest 2", ""],
                  ["9-11 rounds", "Lowest 3-4", "Average  x  0.96"],
                  ["12-14 rounds", "Lowest 4-5", "Average  x  0.96"],
                  ["15-16 rounds", "Lowest 6", "Average  x  0.96"],
                  ["17-18 rounds", "Lowest 7", "Average  x  0.96"],
                  ["19 rounds", "Lowest 8", "Average  x  0.96"],
                  ["20+ rounds", "Best 8 of last 20", "Standard calculation"],
                ].map(([rounds, used, note]) => (
                  <tr key={rounds} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{rounds}</td>
                    <td className="py-2.5 px-4 text-lime-600 dark:text-lime-400 font-medium">{used}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{note}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/golf-handicap-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


